package com.socialblog.comment.application;import com.fasterxml.jackson.core.JsonProcessingException;import com.fasterxml.jackson.databind.ObjectMapper;import com.socialblog.comment.domain.*;import com.socialblog.comment.web.CorrelationIdProvider;import org.springframework.stereotype.Component;import java.time.Instant;import java.util.*;
@Component public class DomainEventFactory{private final ObjectMapper json;private final CorrelationIdProvider ids;public DomainEventFactory(ObjectMapper j,CorrelationIdProvider i){json=j;ids=i;}public OutboxEvent created(Comment c,UUID recipient){Map<String,Object>p=new LinkedHashMap<>();p.put("commentId",c.getId());p.put("articleId",c.getArticleId());p.put("authorId",c.getAuthorId());p.put("parentId",c.getParentId());p.put("recipientId",recipient);p.put("content",c.getContent());return event("CommentCreated",c,p);}public OutboxEvent deleted(Comment c){return event("CommentDeleted",c,Map.of("commentId",c.getId(),"articleId",c.getArticleId(),"authorId",c.getAuthorId()));}private OutboxEvent event(String type,Comment c,Map<String,Object>p){UUID id=UUID.randomUUID();Instant now=Instant.now();Map<String,Object>e=new LinkedHashMap<>();e.put("eventId",id);e.put("eventType",type);e.put("eventVersion",1);e.put("occurredAt",now);e.put("correlationId",ids.current());e.put("actorId",c.getAuthorId());e.put("payload",p);try{return new OutboxEvent(id,c.getId(),type,json.writeValueAsString(e),now);}catch(JsonProcessingException x){throw new IllegalStateException(x);}}}
